import{_ as o,o as a,c,ae as d}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.2.zh-CN.md","filePath":"releases/1.8.2.zh-CN.md"}'),i={name:"releases/1.8.2.zh-CN.md"};function l(t,e,r,s,n,h){return a(),c("div",null,[...e[0]||(e[0]=[d('<h3 id="核心亮点" tabindex="-1">核心亮点 <a class="header-anchor" href="#核心亮点" aria-label="Permalink to &quot;核心亮点&quot;">​</a></h3><p>本次版本补完了 <code>1.8.0</code> 与 <code>1.8.1</code> 启动的语言支持收口工作。前端设置项、侧边栏、任务与提供商语言配置、诊断区、概念笔记设置以及快速工作流等界面文案，现在会更稳定地跟随 Obsidian 当前语言，而不是在升级后仍局部残留英文。</p><p>同时，这一版把文档状态重新拉齐到了代码现状。此前尚未完全对齐的多语 README，现已按英文原始 README 一次性补齐，包括语言架构、配置细节与故障排查章节。发布门禁也进一步收紧：现在会在发布前检查 locale 覆盖、翻译版 README 英文泄漏、硬编码 UI 文案以及 <code>ref/**</code> 工具链隔离，避免语言支持继续以不完整状态进入版本发布。</p><h3 id="破坏性更新" tabindex="-1">破坏性更新 <a class="header-anchor" href="#破坏性更新" aria-label="Permalink to &quot;破坏性更新&quot;">​</a></h3><ul><li><strong>无需用户手动迁移</strong>：现有安装升级后继续沿用当前行为。<code>uiLocale: auto</code> 仍然跟随 Obsidian，既有任务输出语言配置也无需手动调整。</li></ul><h3 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h3><ul><li><code>feat</code>: 扩展前端 UI locale 覆盖，使已支持的 Obsidian 语言在设置页、侧边栏与关键运行时文案上更少回退到英文。</li><li><code>feat</code>: 新增翻译版 README 英文泄漏审计，以及围绕 <code>ref/**</code> 的工具链隔离校验。</li><li><code>feat</code>: 新增或补强 provider 配置、剩余设置表面和 i18n 审计脚本配置的 locale 覆盖测试。</li><li><code>feat</code>: 预览弹窗现已支持将 Mermaid、JSON Canvas、Vega-Lite 预览导出为 <code>.png</code>，并继续保留 <code>.svg</code> 与原始产物保存链路。</li><li><code>feat</code>: 新增预览/导出主题解析契约，使 Mermaid、Canvas 与 Vega-Lite 预览跟随当前 Obsidian 明暗主题，而不是固定停留在错误配色上。</li><li><code>feat</code>: HTML 图表产物现在具备专门的 fallback 预览路径，因此 <code>_diagram.html</code> 输出也可以直接在预览弹窗中打开，而不再只退化为转义源码文本。</li><li><code>feat</code>: HTML fallback 预览现在也会跟随解析后的 Obsidian 预览主题，而不再绑定浏览器或系统默认配色。</li><li><code>feat</code>: 扩展受控的 Vega-Lite 适配模板，使 spec-first 图表生成在原有笛卡尔图表之外，新增支持 <code>scatter</code>、<code>pie</code> 与 <code>table</code> 提示类型。</li><li><code>feat</code>: 规划器现在会为 Vega-Lite 图表预填首选模板，因此当 LLM 省略 <code>layoutHints.chartType</code> 时，趋势、占比、对比与排行类笔记仍可回落到 <code>line</code>、<code>pie</code>、<code>scatter</code> 或 <code>table</code> 默认值。</li></ul><h3 id="bug-修复" tabindex="-1">Bug 修复 <a class="header-anchor" href="#bug-修复" aria-label="Permalink to &quot;Bug 修复&quot;">​</a></h3><ul><li><code>fix</code>: 修复 <code>1.8.0</code> / <code>1.8.1</code> 中升级后前端部分文案仍可能停留在英文、未随 Obsidian 语言切换的问题。</li><li><code>fix</code>: <code>uiLocale: auto</code> 现在会将 <code>fr-CA</code>、<code>es-419</code>、<code>pt-PT</code>、<code>zh-Hans</code>、<code>zh-Hant-HK</code> 等区域或书写体系变体映射到最近的已发布 locale，而不是直接回退到英文。</li><li><code>fix</code>: 补齐高级语言设置、重试与诊断控制、概念笔记输出设置、翻译设置、快速工作流等区域残留的未翻译标签。</li><li><code>fix</code>: 将剩余多语 README 与英文原始 README 完整对齐，补齐语言支持与故障排查等章节内容。</li><li><code>fix</code>: 去除预览 iframe、Mermaid、JSON Canvas 与 Vega-Lite 导出中的硬编码明暗外观，使预览与导出快照更稳定地贴合当前 Obsidian 主题。</li><li><code>fix</code>: 生成的 Mermaid 产物会先通过校验，再进入预览/导出链路，解析失败会更早暴露，而不会继续向后传播无效图表。</li></ul><h3 id="重构与杂项" tabindex="-1">重构与杂项 <a class="header-anchor" href="#重构与杂项" aria-label="Permalink to &quot;重构与杂项&quot;">​</a></h3><ul><li><code>refactor</code>: 将新增 locale 文案收敛到共享 locale 扩展目录，并保持核心语言目录同步。</li><li><code>chore</code>: 强化 TypeScript、Jest 与审计脚本对 <code>ref/**</code> 的隔离，避免本地参考仓污染正常构建与测试范围。</li><li><code>docs</code>: 更新 README 版本号与多语语言支持文档，使其与当前实际发货实现一致。</li></ul><h3 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h3><p>感谢 <code>@Jacobinwwey</code> 推进本次语言覆盖补齐、README 对齐与发布验证门禁强化。</p>',13)])])}const b=o(i,[["render",l]]);export{u as __pageData,b as default};
